namespace BlazorApp.Services;

public class NotificationItem
{
    public int Id { get; set; }
    public string Message { get; set; } = string.Empty;
    public DateTime Timestamp { get; set; }
}

public class NotificationService
{
    private int _nextId = 1;
    private readonly string[] _messages =
    [
        "New deployment completed successfully",
        "User 'admin' logged in from a new device",
        "Database backup finished",
        "Memory usage exceeded 80% threshold",
        "New comment on pull request #42",
        "Build pipeline failed for branch 'feature/auth'",
        "Certificate expiring in 7 days",
        "New team member joined the workspace",
        "Scheduled maintenance window approaching",
        "API rate limit warning: 90% consumed"
    ];

    public Task<List<NotificationItem>> GetInitialNotificationsAsync()
    {
        var notifications = Enumerable.Range(0, 3).Select(_ => GenerateNotification()).ToList();
        return Task.FromResult(notifications);
    }

    public Task<List<NotificationItem>> CheckForNewNotificationsAsync()
    {
        // Simulate: ~50% chance of a new notification each poll
        if (Random.Shared.Next(2) == 0)
        {
            return Task.FromResult(new List<NotificationItem> { GenerateNotification() });
        }

        return Task.FromResult(new List<NotificationItem>());
    }

    private NotificationItem GenerateNotification()
    {
        return new NotificationItem
        {
            Id = _nextId++,
            Message = _messages[Random.Shared.Next(_messages.Length)],
            Timestamp = DateTime.Now
        };
    }
}

