@page "/notifications"
@rendermode InteractiveServer
@using BlazorApp.Services
@inject NotificationService NotificationService
@implements IDisposable

<PageTitle>Notifications</PageTitle>

<h1>
    Notifications
    <span class="badge bg-primary rounded-pill">@notifications.Count</span>
</h1>

@if (notifications.Count == 0)
{
    <p><em>No notifications.</em></p>
}
else
{
    <ul class="list-group">
        @foreach (var notification in notifications.OrderByDescending(n => n.Timestamp))
        {
            <li class="list-group-item d-flex justify-content-between align-items-start">
                <div>@notification.Message</div>
                <small class="text-muted">@notification.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    [PersistentState]
    public List<NotificationItem>? RestoredNotifications { get; set; }

    private List<NotificationItem> notifications = new();
    private CancellationTokenSource? _cts;

    protected override async Task OnInitializedAsync()
    {
        if (RestoredNotifications is not null)
        {
            // Restored from prerender — don't re-fetch
            notifications = RestoredNotifications;
        }
        else
        {
            // First render (prerender): load initial data
            notifications = await NotificationService.GetInitialNotificationsAsync();
            RestoredNotifications = notifications;
        }
    }

    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            // Only runs when interactive — never during prerender
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken cancellationToken)
    {
        while (!cancellationToken.IsCancellationRequested)
        {
            await Task.Delay(TimeSpan.FromSeconds(5), cancellationToken);

            var newItems = await NotificationService.CheckForNewNotificationsAsync();
            if (newItems.Count > 0)
            {
                notifications.AddRange(newItems);
                await InvokeAsync(StateHasChanged);
            }
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

